-- Fechas de demostracion actualizadas desde el 23 de julio de 2026.
update citas
set fecha_hora_inicio = case codigo_gestion
        when 'ORALA001' then timestamp '2026-07-23 08:30:00'
        when 'ORALA002' then timestamp '2026-07-23 09:00:00'
        when 'ORALA003' then timestamp '2026-07-23 15:00:00'
        when 'ORALA004' then timestamp '2026-07-24 08:30:00'
        when 'ORALA005' then timestamp '2026-07-24 15:00:00'
        when 'ORALA006' then timestamp '2026-07-25 09:00:00'
        when 'RDCP6BDR' then timestamp '2026-07-27 08:30:00'
        else fecha_hora_inicio
    end,
    fecha_hora_fin = case codigo_gestion
        when 'ORALA001' then timestamp '2026-07-23 09:00:00'
        when 'ORALA002' then timestamp '2026-07-23 09:30:00'
        when 'ORALA003' then timestamp '2026-07-23 15:30:00'
        when 'ORALA004' then timestamp '2026-07-24 09:00:00'
        when 'ORALA005' then timestamp '2026-07-24 15:30:00'
        when 'ORALA006' then timestamp '2026-07-25 09:30:00'
        when 'RDCP6BDR' then timestamp '2026-07-27 09:00:00'
        else fecha_hora_fin
    end,
    fecha_actualizacion = timestamp '2026-07-23 08:00:00'
where codigo_gestion in (
    'ORALA001', 'ORALA002', 'ORALA003', 'ORALA004',
    'ORALA005', 'ORALA006', 'RDCP6BDR'
);

update pacientes
set codigo_paciente = 'PAC-' || lpad(id::text, 6, '0')
where codigo_paciente is null or btrim(codigo_paciente) = '';

alter table pacientes alter column codigo_paciente set not null;

select setval(pg_get_serial_sequence('usuarios', 'id'), coalesce((select max(id) from usuarios), 1), true);
select setval(pg_get_serial_sequence('servicios', 'id'), coalesce((select max(id) from servicios), 1), true);
select setval(pg_get_serial_sequence('horarios', 'id'), coalesce((select max(id) from horarios), 1), true);
select setval(pg_get_serial_sequence('pacientes', 'id'), coalesce((select max(id) from pacientes), 1), true);
select setval(pg_get_serial_sequence('citas', 'id'), coalesce((select max(id) from citas), 1), true);
select setval(pg_get_serial_sequence('fichas_clinicas', 'id'), coalesce((select max(id) from fichas_clinicas), 1), true);
select setval(pg_get_serial_sequence('anamnesis', 'id'), coalesce((select max(id) from anamnesis), 1), true);
select setval(pg_get_serial_sequence('odontogramas', 'id'), coalesce((select max(id) from odontogramas), 1), true);
select setval(pg_get_serial_sequence('odontograma_dientes', 'id'), coalesce((select max(id) from odontograma_dientes), 1), true);
select setval(pg_get_serial_sequence('odontograma_caras', 'id'), coalesce((select max(id) from odontograma_caras), 1), true);
select setval(pg_get_serial_sequence('periodontogramas', 'id'), coalesce((select max(id) from periodontogramas), 1), true);
select setval(pg_get_serial_sequence('periodontograma_dientes', 'id'), coalesce((select max(id) from periodontograma_dientes), 1), true);
select setval(pg_get_serial_sequence('periodontograma_sitios', 'id'), coalesce((select max(id) from periodontograma_sitios), 1), true);
select setval(pg_get_serial_sequence('recetas', 'id'), coalesce((select max(id) from recetas), 1), true);
select setval(pg_get_serial_sequence('receta_detalles', 'id'), coalesce((select max(id) from receta_detalles), 1), true);
select setval(pg_get_serial_sequence('radiografias', 'id'), coalesce((select max(id) from radiografias), 1), true);
select setval(pg_get_serial_sequence('analisis_radiografias', 'id'), coalesce((select max(id) from analisis_radiografias), 1), true);

commit;
